327	      (btn) =>
328	        btn.getAttribute('aria-expanded') !== null &&
329	        !btn.textContent?.includes('Next') &&
330	        !btn.textContent?.includes('Back') &&
331	        !btn.textContent?.includes('Close') &&
332	        !btn.textContent?.includes('mock-placement')
333	    );
334	
335	    if (labelButtons.length > 0) {
336	      await user.click(labelButtons[labelButtons.length - 1]);
337	      const appLabel = await screen.findByText('app=mock-appset-2');
338	      await user.click(appLabel);
339	    }
340	
341	    // Click Next to proceed to review step
342	    const nextButtons = screen.getAllByText('Next');
343	    await user.click(nextButtons[nextButtons.length - 1]);
344	
345	    // Step 3 - review and assign
346	    expect(screen.getByText('Assign')).toBeEnabled();
347	    expect(screen.getByText('Back')).toBeEnabled();
348	    expect(screen.getByText('Cancel')).toBeEnabled();
349	
350	    screen.getByText(/Policy/i, { selector: 'span' });
351	    expect(screen.getByText('Policy name:')).toBeInTheDocument();
352	    expect(screen.getByText('Clusters:')).toBeInTheDocument();
353	    expect(screen.getByText('Replication type:')).toBeInTheDocument();
354	    expect(screen.getByText('Sync interval:')).toBeInTheDocument();
355	    expect(screen.getByText('Application resource:')).toBeInTheDocument();
356	    expect(screen.getByText('PVC label selector:')).toBeInTheDocument();
357	
358	    expect(screen.getByText('mock-policy-1')).toBeInTheDocument();
359	    expect(screen.getByText('east-1, west-1')).toBeInTheDocument();
360	    expect(screen.getByText('Asynchronous')).toBeInTheDocument();
361	    expect(screen.getByText('5 minutes')).toBeInTheDocument();
362	    expect(screen.getByText('mock-placement-2')).toBeInTheDocument();
363	    expect(screen.getByText('app=mock-appset-2')).toBeInTheDocument();
364	  });
365	});

