258	              variant="plain"
259	              onClick={onClearAll}
260	              aria-label={t('Clear input value')}
261	            >
262	              <TimesIcon aria-hidden />
263	            </Button>
264	          </TextInputGroupUtilities>
265	        </TextInputGroup>
266	      </MenuToggle>
267	    );
268	  };
269	
270	  const options = () => {
271	    if (visibleOptions.length === 0) {
272	      return (
273	        <SelectOption key="disabled-options" value={DISABLED} isDisabled>
274	          {t('No option found')}
275	        </SelectOption>
276	      );
277	    }
278	
279	    return visibleOptions.map((opt) => (
280	      <SelectOption
281	        key={opt.value}
282	        value={opt.value}
283	        description={opt.description}
284	        hasCheckbox={variant === 'checkbox'}
285	        isSelected={selections.includes(opt.value)}
286	      >
287	        {opt.label}
288	      </SelectOption>
289	    ));
290	  };
291	
292	  return (
293	    <Select
