295	      className={className}
296	      onSelect={onSelect}
297	      isOpen={isOpen}
298	      selected={selections}
299	      onOpenChange={(open) => setIsOpen(open)}
300	      toggle={toggle}
301	      isDisabled={isDisabled}
302	      popperProps={popperProps}
303	      data-test={props['data-test']}
304	    >
