  1	import * as React from 'react';
  2	import TimesIcon from '@patternfly/react-icons/dist/esm/icons/times-icon';
  3	import {
  4	  Select,
  5	  SelectList,
  6	  SelectOption,
  7	  MenuToggle,
  8	  MenuToggleElement,
  9	  MenuToggleStatus,
 10	  TextInputGroup,
 11	  TextInputGroupMain,
 12	  TextInputGroupUtilities,
 13	  Button,
 14	} from '@patternfly/react-core';
 15	import { useCustomTranslation } from '../useCustomTranslationHook';
 16	
 17	export const SingleSelectDropdown: React.FC<SingleSelectDropdownProps> = ({
 18	  onChange,
 19	  selectOptions,
 20	  selectedKey = '',
 21	  validated,
 22	  className,
 23	  valueLabelMap,
 24	  ...props
 25	}) => {
 26	  const { t } = useCustomTranslation();
 27	
 28	  const [isOpen, setIsOpen] = React.useState(false);
 29	  const [newOptions, setNewOptions] = React.useState<JSX.Element[]>([]);
 30	  const [status, setStatus] = React.useState<MenuToggleStatus>();
 31	  const [filterValue, setFilterValue] = React.useState('');
 32	  const [inputValue, setInputValue] = React.useState('');
 33	  const [newOptionVal, setNewOptionVal] = React.useState('');
 34	  const DISABLED = '__disabled__';
 35	
 36	  React.useEffect(() => {
 37	    if (selectedKey) {
 38	      const matchedOption = React.Children.toArray(selectOptions).find(
 39	        (opt: any) => opt.props?.value === selectedKey
 40	      ) as React.ReactElement | undefined;
 41	
 42	      if (matchedOption) {
 43	        setInputValue(String(matchedOption.props.children));
 44	      } else {
 45	        setInputValue(selectedKey);
 46	      }
 47	    } else {
 48	      setInputValue('');
 49	    }
 50	  }, [selectedKey, selectOptions]);
 51	
 52	  React.useEffect(() => {
 53	    let derivedValidated = validated === 'error' ? 'danger' : validated;
 54	    setStatus(
 55	      derivedValidated && derivedValidated !== 'default'
 56	        ? (derivedValidated as MenuToggleStatus)
 57	        : undefined
 58	    );
 59	  }, [validated]);
 60	
 61	  React.useEffect(() => {
 62	    if (filterValue) {
 63	      setNewOptionVal(filterValue);
 64	    }
 65	  }, [filterValue]);
 66	
 67	  const filteredOptions = React.useMemo(() => {
 68	    let options = selectOptions;
 69	    const lowerValue = filterValue.toLowerCase();
 70	    if (props.hasInlineFilter && filterValue) {
 71	      options = selectOptions.filter((option) =>
 72	        String(option.props.children).toLowerCase().includes(lowerValue)
 73	      );
 74	
 75	      const exactMatchExists = selectOptions.some(
 76	        (option) => String(option.props.children).toLowerCase() === lowerValue
 77	      );
 78	
 79	      if (options.length === 0) {
 80	        if (props.isCreatable && filterValue.trim() && !exactMatchExists) {
 81	          options = [
 82	            <SelectOption key={filterValue} value={filterValue}>
 83	              {t('Create "{{filterValue}}"', { filterValue })}
 84	            </SelectOption>,
 85	          ];
 86	        } else {
 87	          options = [
 88	            <SelectOption key={DISABLED} value={DISABLED} isDisabled>
 89	              {t('No option found')}
 90	            </SelectOption>,
 91	          ];
 92	        }
 93	      } else if (props.isCreatable && filterValue.trim() && !exactMatchExists) {
 94	        options = [
 95	          <SelectOption key={filterValue} value={filterValue}>
 96	            {t('Create "{{filterValue}}"', { filterValue })}
 97	          </SelectOption>,
 98	          ...options,
 99	        ];
100	      }
101	    }
102	
103	    return options;
104	  }, [filterValue, props.hasInlineFilter, props.isCreatable, selectOptions, t]);
105	
106	  const allOptions =
107	    newOptions.length > 0
108	      ? filteredOptions.concat(newOptions)
109	      : filteredOptions;
110	
111	  const onSelect = React.useCallback(
112	    (_event: React.MouseEvent | React.ChangeEvent, selection: string) => {
113	      /**
114	       * For case when the dropdownitem that we want to show on UI (label)
115	       * and its corresponding value that we want to store in the redux-state is different.
116	       * e.g: OSDSizeDropdown
117	       */
118	      const value = valueLabelMap
119	        ? Object.keys(valueLabelMap).find(
120	            (key) => valueLabelMap[key] === selection
121	          )
122	        : selection;
123	      if (!value) return;
124	
125	      if (value === newOptionVal) {
126	        const newValue = newOptionVal;
127	        if (newValue) {
128	          const newOption = (
129	            <SelectOption key={newValue} value={newValue}>
130	              {newValue}
131	            </SelectOption>
132	          );
