// Find all expandable toggles and look for the PVC label selector
// In PF v6, MenuToggle with typeahead variant renders a <div>, not a <button>,
// so we query by [aria-expanded] attribute instead of role='button'.
const allExpandable = document.querySelectorAll('[aria-expanded]');
const labelButtons = Array.from(allExpandable).filter(
  (btn) =>
    !btn.textContent?.includes('Next') &&
    !btn.textContent?.includes('Back') &&
    !btn.textContent?.includes('Close') &&
    !btn.textContent?.includes('mock-placement')
);

